function bridgeTokens(address token, uint256 amount, uint256 chainId) external {
    IERC20(token).transferFrom(msg.sender, address(this), amount);
    emit TokensBridged(msg.sender, token, amount, chainId);
}

chosen:
**Vulnerability: Arbitrary Token Bridging Without Whitelist**

Any token address can be bridged, including:
1. Fee-on-transfer tokens: the contract receives less than `amount`, but the event logs the full `amount` — the destination chain mints more than was locked
2. Rebasing tokens: balance changes after deposit corrupt accounting
3. Malicious token contracts: `transferFrom` can execute arbitrary code

**Fix:**
```solidity
mapping(address => bool) public supportedTokens;

function bridgeTokens(address token, uint256 amount, uint256 chainId) external {
    require(supportedTokens[token], "token not supported");
    uint256 before = IERC20(token).balanceOf(address(this));
    IERC20(token).transferFrom(msg.sender, address(this), amount);
    uint256 actual = IERC20(token).balanceOf(address(this)) - before;
    emit TokensBridged(msg.sender, token, actual, chainId);  // use actual
}
```

