function withdrawAll() external onlyOwner {
    payable(owner).transfer(address(this).balance);
    for (uint i = 0; i < tokens.length; i++) {
        IERC20(tokens[i]).transfer(owner, IERC20(tokens[i]).balanceOf(address(this)));
    }
}

chosen:
**Vulnerability: Transfer Can Fail Silently + Unbounded Loop**

1. `IERC20.transfer` returns a `bool` but the return value is not checked. If a token's `transfer` returns `false` (non-reverting ERC-20), the loop continues without actually transferring that token.
2. If `tokens.length` grows large, this function will hit the block gas limit and become permanently uncallable.

**Fix:**
```solidity
function withdrawAll() external onlyOwner {
    uint256 ethBal = address(this).balance;
    if (ethBal > 0) {
        (bool ok,) = payable(owner).call{value: ethBal}("");
        require(ok, "ETH transfer failed");
    }
    uint256 len = tokens.length;
    require(len <= 50, "too many tokens");  // or use pagination
    for (uint i = 0; i < len; i++) {
        uint256 bal = IERC20(tokens[i]).balanceOf(address(this));
        if (bal > 0) {
            bool ok = IERC20(tokens[i]).transfer(owner, bal);
            require(ok, "token transfer failed");
        }
    }
}
```

prompt:
function setFee(uint256 newFee) external onlyOwner {
    fee = newFee;
}

chosen:
**Issue: No Upper Bound on Fee**

The owner can set `fee` to any value, including 100% or more. If users trust the protocol and do not monitor every `setFee` transaction, the owner can front-run user deposits with a fee change, extracting near-total value from the next transaction.

**Fix — cap the fee and emit an event:**
```solidity
uint256 public constant MAX_FEE = 500; // 5% in basis points

function setFee(uint256 newFee) external onlyOwner {
    require(newFee <= MAX_FEE, "fee too high");
    emit FeeUpdated(fee, newFee);
    fee = newFee;
}
```
Combining with a timelock for parameter changes is also recommended for protocols with significant TVL.
